<template>
  <div class="bg-white dark:bg-gray-800 shadow sm:rounded-lg">
    <div class="px-4 py-5 sm:p-6">
      <h3 class="text-lg leading-6 font-medium text-gray-900 dark:text-gray-100 mb-4">
        Interaction History
      </h3>
      
      <div v-if="loading && interactions.length === 0" class="text-gray-500 dark:text-gray-400 text-sm">
        Loading...
      </div>
      
      <div v-else-if="interactions.length === 0" class="text-gray-500 dark:text-gray-400 text-sm">
        No interactions found.
      </div>
      
      <div v-else class="flex flex-col">
        <div class="-my-2 overflow-x-auto sm:-mx-6 lg:-mx-8">
          <div class="py-2 align-middle inline-block min-w-full sm:px-6 lg:px-8">
            <div class="shadow overflow-hidden border-b border-gray-200 dark:border-gray-700 sm:rounded-lg">
              <table class="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                <thead class="bg-gray-50 dark:bg-gray-700">
                  <tr>
                    <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">
                      Date
                    </th>
                    <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">
                      User
                    </th>
                    <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">
                      Model
                    </th>
                    <th scope="col" class="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-300 uppercase tracking-wider">
                      Cost
                    </th>
                    <th scope="col" class="relative px-6 py-3">
                      <span class="sr-only">View</span>
                    </th>
                  </tr>
                </thead>
                <tbody class="bg-white dark:bg-gray-800 divide-y divide-gray-200 dark:divide-gray-700">
                  <tr v-for="item in interactions" :key="item.id">
                    <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      {{ formatDate(item.timestamp) }}
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-900 dark:text-gray-100">
                      {{ item.user }}
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      {{ item.model }}
                    </td>
                     <td class="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                      ${{ item.cost ? parseFloat(item.cost).toFixed(6) : '0.000000' }}
                    </td>
                    <td class="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <router-link :to="'/history/' + item.id" class="text-indigo-600 dark:text-indigo-400 hover:text-indigo-900 dark:hover:text-indigo-300">View</router-link>
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </div>
        
        <div v-if="lastVisible" class="mt-4 flex justify-center">
            <button 
                @click="fetchInteractions" 
                :disabled="loading"
                class="inline-flex items-center px-4 py-2 border border-gray-300 dark:border-gray-600 shadow-sm text-sm font-medium rounded-md text-gray-700 dark:text-gray-200 bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
            >
                {{ loading ? 'Loading...' : 'Load More' }}
            </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { db } from '../firebase';
import { collection, query, orderBy, limit, getDocs, startAfter } from 'firebase/firestore';

export default {
  name: 'History',
  data() {
    return {
      interactions: [],
      loading: false,
      lastVisible: null,
      pageSize: 20
    }
  },
  mounted() {
    this.fetchInteractions();
  },
  methods: {
    async fetchInteractions() {
      if (this.loading) return;
      this.loading = true;
      try {
        let q = query(
            collection(db, "interaction_logs"), 
            orderBy("timestamp", "desc"), 
            limit(this.pageSize)
        );

        if (this.lastVisible) {
            q = query(
                collection(db, "interaction_logs"), 
                orderBy("timestamp", "desc"), 
                startAfter(this.lastVisible),
                limit(this.pageSize)
            );
        }

        const querySnapshot = await getDocs(q);
        
        if (!querySnapshot.empty) {
            this.lastVisible = querySnapshot.docs[querySnapshot.docs.length - 1];
            querySnapshot.forEach((doc) => {
                this.interactions.push({ id: doc.id, ...doc.data() });
            });
            // If we got fewer docs than page size, we reached the end
            if (querySnapshot.size < this.pageSize) {
                this.lastVisible = null;
            }
        } else {
            this.lastVisible = null;
        }

      } catch (e) {
        console.error("Error fetching history:", e);
      } finally {
        this.loading = false;
      }
    },
    formatDate(timestamp) {
        if (!timestamp) return '';
        // Handle Firestore Timestamp or Date object
        const date = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
        return date.toLocaleString();
    }
  }
}
</script>
