import { initializeApp } from "firebase/app";
import { getAuth, GoogleAuthProvider } from "firebase/auth";
import { getFirestore } from "firebase/firestore";

const firebaseConfig = {
    apiKey: process.env.VUE_APP_FIREBASE_API_KEY,
    authDomain: process.env.VUE_APP_FIREBASE_AUTH_DOMAIN,
    projectId: process.env.VUE_APP_FIREBASE_PROJECT_ID,
    storageBucket: process.env.VUE_APP_FIREBASE_STORAGE_BUCKET,
    messagingSenderId: process.env.VUE_APP_FIREBASE_MESSAGING_SENDER_ID,
    appId: process.env.VUE_APP_FIREBASE_APP_ID
};

console.log("Firebase Config Debug:", {
    apiKey: firebaseConfig.apiKey ? "Set" : "Missing",
    authDomain: firebaseConfig.authDomain,
    projectId: firebaseConfig.projectId
});

if (
    !firebaseConfig.apiKey ||
    firebaseConfig.apiKey === 'YOUR_API_KEY' ||
    !firebaseConfig.authDomain ||
    firebaseConfig.authDomain.includes('YOUR_PROJECT_ID')
) {
    const msg = "Firebase Configuration Error: It looks like you haven't updated the VUE_APP_ variables in your .env file with your actual Firebase project details.";
    console.error(msg);
    alert(msg);
}

const app = initializeApp(firebaseConfig);
const auth = getAuth(app);
const db = getFirestore(app);
const googleProvider = new GoogleAuthProvider();

export { auth, db, googleProvider };
