<template>
  <div class="bg-white shadow sm:rounded-lg">
    <div class="px-4 py-5 sm:p-6" v-if="interaction">
      <div class="flex items-center justify-between mb-6">
        <h3 class="text-lg leading-6 font-medium text-gray-900">
          Interaction Details
        </h3>
        <router-link to="/history" class="text-sm text-indigo-600 hover:text-indigo-900">
            &larr; Back to History
        </router-link>
      </div>

      <div class="border-t border-gray-200">
        <dl>
          <div class="bg-gray-50 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500">ID</dt>
            <dd class="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">{{ interaction.id }}</dd>
          </div>
          <div class="bg-white px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500">Timestamp</dt>
            <dd class="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">{{ formatDate(interaction.timestamp) }}</dd>
          </div>
          <div class="bg-gray-50 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500">User</dt>
            <dd class="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">{{ interaction.user }}</dd>
          </div>
          <div class="bg-white px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500">Model</dt>
            <dd class="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">{{ interaction.model }}</dd>
          </div>
           <div class="bg-gray-50 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500">Cost</dt>
            <dd class="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">${{ interaction.cost }}</dd>
          </div>
          <div class="bg-white px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500">Response</dt>
            <dd class="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2 whitespace-pre-wrap">{{ interaction.response }}</dd>
          </div>
          <div class="bg-gray-50 px-4 py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
            <dt class="text-sm font-medium text-gray-500">Payload</dt>
            <dd class="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                 <pre class="text-xs bg-gray-100 p-2 rounded overflow-x-auto whitespace-pre-wrap">{{ JSON.stringify(interaction.payload, null, 2) }}</pre>
            </dd>
          </div>
        </dl>
      </div>
    </div>
    <div v-else-if="loading" class="p-6 text-gray-500">
        Loading...
    </div>
    <div v-else class="p-6 text-red-500">
        Interaction not found.
    </div>
  </div>
</template>

<script>
import { db } from '../firebase';
import { doc, getDoc } from 'firebase/firestore';

export default {
  name: 'HistoryDetail',
  data() {
    return {
      interaction: null,
      loading: true
    }
  },
  async mounted() {
    const id = this.$route.params.id;
    if (id) {
        await this.fetchInteraction(id);
    }
  },
  methods: {
    async fetchInteraction(id) {
        try {
            const docRef = doc(db, "interaction_logs", id);
            const docSnap = await getDoc(docRef);
            
            if (docSnap.exists()) {
                this.interaction = { id: docSnap.id, ...docSnap.data() };
            } else {
                console.error("No such document!");
            }
        } catch (e) {
            console.error("Error fetching doc:", e);
        } finally {
            this.loading = false;
        }
    },
    formatDate(timestamp) {
        if (!timestamp) return '';
        const date = timestamp.toDate ? timestamp.toDate() : new Date(timestamp);
        return date.toLocaleString();
    }
  }
}
</script>
